import { Injectable } from '@angular/core';
import { Observable, of } from 'rxjs';

import { ISelectOption } from '../shared/grid-form/option-base';



@Injectable({
  providedIn: 'root'
})
export class MockDatasService {

  constructor() { }

  getOptions(): Observable<ISelectOption[]> {
    const options: ISelectOption[] = [];

    for (let i = 0; i < 10; i++) {
      options.push({
        value: i,
        label: 'Option ' + (i + 1)
      });
    }
    return of(options);
  }
}
