import { coerceBooleanProperty } from '@angular/cdk/coercion';
import { Component, Input, OnInit } from '@angular/core';

import { ILanguageOption } from '../language-option';



@Component({
  selector: 'app-input-nselect',
  templateUrl: './input-nselect.component.html',
  styleUrls: ['./input-nselect.component.scss'],
  exportAs: 'appInputNSelect',
  host: {
    '[attr.class]': '"input-select d-flex mw-100 " + class'
  }
})
export class InputNSelectComponent implements OnInit {
  @Input() options: ILanguageOption[] = [{
    code: '01',
    value: 'gb',
    label: '中文'
  }];
  @Input() set showPrefix(value: boolean) {
    this._showPrefix = coerceBooleanProperty(value);
  }
  get showPrefix(): boolean {
    return this._showPrefix;
  }
  @Input() class: string;

  selectedValue: ILanguageOption;
  private _showPrefix: boolean = false;

  constructor() { }

  ngOnInit(): void {
  }
}
