import { Directive, ElementRef, OnInit, Renderer2 } from '@angular/core';

@Directive({
  selector: '[appFieldGroup]'
})
export class FieldGroupDirective implements OnInit {

  constructor(
    private elementRef: ElementRef<HTMLElement>,
    private renderer: Renderer2
  ) { }

  ngOnInit(): void {
    const element = this.elementRef.nativeElement;
    const length = element.parentElement.children.length;

    this.renderer.addClass(element, 'row');
    this.renderer.addClass(element, 'col-12');
    this.renderer.addClass(element, 'col-lg-' + Math.ceil(12 / length));
    this.renderer.addClass(element, 'no-gutters');
    this.renderer.addClass(element, 'field-group');
  }

}
