import { Component, EventEmitter, Input, OnInit, Output, TemplateRef, ViewChild } from '@angular/core';
import { FormControl } from '@angular/forms';
import { coerceBooleanProperty } from '@angular/cdk/coercion';
import { MatAutocompleteSelectedEvent } from '@angular/material/autocomplete';
import { MatOptionParentComponent } from '@angular/material/core';
import { interval, Observable, of } from 'rxjs';
import { debounce, finalize, map, startWith, switchMap } from 'rxjs/operators';

import { MockDatasService } from 'app/admin/bank-features/services/mock-datas.service';
import { ISelectOption } from '../option-base';



@Component({
  selector: 'app-search-input',
  templateUrl: './search-input.component.html',
  styleUrls: ['./search-input.component.scss'],
  exportAs: 'appSearchInput',
  host: {
    '[attr.class]': '"search-input d-flex mw-100 " + class'
  }
})
export class SearchInputComponent implements MatOptionParentComponent, OnInit {
  @Input() set options(values: ISelectOption[]) {
    this.optionValues = values;
    const selectedOptions = this.getOptions(true);
    setTimeout(() => {
      this.change.emit(selectedOptions);
    });
    if (this.searchCtrl) {
      setTimeout(() => {
        this.searchCtrl.updateValueAndValidity({ onlySelf: true, emitEvent: true });
      });
    }
  }
  get options(): ISelectOption[] {
    return this.optionValues;
  }
  @Input() source: (entry: string) => Observable<ISelectOption[]>;
  @Input() disableRipple: boolean = false;
  @Input() multiple: boolean = false;
  @Input() inertGroups: boolean = false;
  @Input() enableSort = true;
  @Input() set showPrefix(value: boolean) {
    this._showPrefix = coerceBooleanProperty(value);
  }
  get showPrefix(): boolean {
    return this._showPrefix;
  }
  @Input() optionTemplate: TemplateRef<HTMLElement | HTMLCollection | string>;
  @Input() class: string;
  @Output() change = new EventEmitter<ISelectOption[]>();
  @Output() close = new EventEmitter<ISelectOption[]>();

  searchCtrl = new FormControl();
  selectedValue: ISelectOption;
  filteredOptions: Observable<ISelectOption[]>;
  loading = false;

  @ViewChild('defaultOptionTemplate', { static: true }) private defaultOptionTemplate: TemplateRef<string>;
  private optionValues: ISelectOption[];
  private toggling = false;
  private _showPrefix: boolean = false;

  constructor(private datasService: MockDatasService) {
    this.source = () => this.datasService.getOptions();
  }

  ngOnInit() {
    this.optionTemplate = this.optionTemplate || this.defaultOptionTemplate;
    this.filteredOptions = this.searchCtrl.valueChanges.pipe(
      debounce((entry) => {
        return interval(entry !== null && !this.toggling && this.source ? 300 : 0);
      }),
      startWith(''),
      switchMap((entry) => {
        let restOptions: ISelectOption[];

        if (entry !== null && !this.toggling && this.source) {
          this.toggling = false;
          setTimeout(() => {
            this.loading = true;
          });
          return this.source(entry).pipe(
            map((options) => {
              return options.filter((item) => {
                return !item.selected && item.label.toString().toLowerCase().indexOf(entry) >= 0;
              });
            }),
            finalize(() => {
              this.loading = false;
            })
          );
        }
        restOptions = entry ? this.filterOptions(entry) : this.getOptions(false);
        this.toggling = false;
        return of(restOptions);
      })
    );
  }

  onOptionSelected(event: MatAutocompleteSelectedEvent) {
    const selectedOptions = this.getOptions(true);

    this.toggling = true;
    setTimeout(() => {
      this.change.emit(selectedOptions);
      this.searchCtrl.updateValueAndValidity({ onlySelf: true, emitEvent: true });
    });
  }

  getLabel(option: ISelectOption): string {
    return option && option.label ? option.label : '';
  }

  private getOptions(selected: boolean): ISelectOption[] {
    if (!this.options) {
      return [];
    }
    if (this.enableSort) {
      this.options.sort((a, b) => {
        const reulst = a.order - b.order;
        return isNaN(reulst) ? 0 : reulst;
      });
    }
    return this.options.filter((item) => !!item.selected === selected);
  }

  private filterOptions(value: string): ISelectOption[] {
    if (typeof value !== 'string') {
      return;
    }
    const filterValue = value.toLowerCase();

    if (!this.options) {
      return [];
    }
    if (this.enableSort) {
      this.options.sort((a, b) => {
        const reulst = a.order - b.order;
        return isNaN(reulst) ? 0 : reulst;
      });
    }

    return this.options.filter((item) => {
      return !item.selected && item.label.toString().toLowerCase().indexOf(filterValue) >= 0;
    });
  }
}
