import { AfterViewInit, Component, ElementRef, EventEmitter, Input, OnDestroy, OnInit, Output, Renderer2, TemplateRef, ViewChild } from '@angular/core';
import { MatPaginator } from '@angular/material/paginator';
import { MatSort } from '@angular/material/sort';
import { of, merge, Subscription } from 'rxjs';
import { catchError, debounceTime, map, startWith, switchMap } from 'rxjs/operators';

import { IDatabase } from 'app/admin/bank-features/services/database';
import { EventService } from 'app/shared/services/event.service';



@Component({
  selector: 'app-database-table',
  templateUrl: './database-table.component.html',
  styleUrls: ['./database-table.component.scss'],
  host: {
    'class': 'd-flex flex-column flex-nowrap w-100 h-100'
  }
})
export class DatabaseTableComponent<T> implements OnInit, AfterViewInit, OnDestroy {
  @Input() database: IDatabase;
  @Input() displayedColumns: Array<string>;
  @Input() displayedHeads: Array<string | TemplateRef<HTMLElement | HTMLCollection | string>>;
  @Output() onSelectedRowChange = new EventEmitter<T>();

  data = [];
  isLoading: boolean;
  resultsLength = 0;
  isRateLimitReached = false;

  @ViewChild('flexFillContainer') private flexFillContainer: ElementRef<HTMLElement>;
  @ViewChild(MatPaginator) private paginator: MatPaginator;
  @ViewChild(MatSort) private sort: MatSort;
  private pageSize = 20;
  private subscription = new Subscription();

  constructor(
    private renderer: Renderer2,
    private eventService: EventService
  ) { }

  ngOnInit(): void {
  }

  ngAfterViewInit(): void {
    this.subscription.add(
      this.eventService.onViewportDimensionChange().pipe(debounceTime(300)).subscribe((change) => {
        if (change.height) {
          this.adjustPageSize();
        }
      })
    );
    // If the user changes the sort order, reset back to the first page.
    this.sort.sortChange.subscribe(() => this.paginator.pageIndex = 0);

    setTimeout(() => {
      this.adjustPageSize();

      merge(this.sort.sortChange, this.paginator.page)
        .pipe(
          startWith({}),
          switchMap(() => {
            this.isLoading = true;
            return this.database!.getData();
          }),
          map((data: Array<any>) => {
            // Flip flag to show that loading has finished.
            this.isLoading = false;
            this.isRateLimitReached = false;
            this.resultsLength = data.length;
  
            return data.slice(this.paginator.pageIndex * this.pageSize, (this.paginator.pageIndex + 1) * this.pageSize);
          }),
          catchError(() => {
            this.isLoading = false;
            // Catch if the GitHub API has reached its rate limit. Return empty data.
            this.isRateLimitReached = true;
            return of([]);
          })
        ).subscribe(data => this.data = data);
    });
  }

  ngOnDestroy(): void {
    this.subscription.unsubscribe();
  }

  onClickRow(event: MouseEvent, row: T): void {
    let trEL = (event.target as HTMLElement);

    event.stopPropagation();
    if (trEL.tagName.toLocaleLowerCase() === 'td') {
      trEL = trEL.parentElement;
    }
    if (trEL) {
      const siblings = trEL.parentElement.querySelectorAll('.table-active');

      siblings.forEach((element) => {
        this.renderer.removeClass(element, 'table-active');
      });
      this.renderer.addClass(trEL, 'table-active');
    }
    this.onSelectedRowChange.emit(row);
  }

  private adjustPageSize(): void {
    const pageSize = Math.floor((this.flexFillContainer.nativeElement.offsetHeight - 34) / 34);

    this.pageSize = Math.max(10, pageSize);
    this.paginator._changePageSize(this.pageSize);
  }
}
