import { Directive, ElementRef, OnInit, Renderer2 } from '@angular/core';

@Directive({
  selector: '[appFieldControl]'
})
export class FieldControlDirective implements OnInit {

  constructor(
    private elementRef: ElementRef<HTMLElement>,
    private renderer: Renderer2
  ) { }

  ngOnInit(): void {
    const element = this.elementRef.nativeElement;
    const length = this.elementRef.nativeElement.parentElement.parentElement.children.length;

    this.renderer.addClass(element, 'col-12');
    this.renderer.addClass(element, 'col-lg-' + (12 - (2 * length)));
    this.renderer.addClass(element, 'field-control');
  }

}
