import { Observable, of } from "rxjs";



export interface IDatabase {
  getData: (params?: any) => Observable<any>
}

export class MockLanguagesDatabase implements IDatabase {
  constructor() {}

  getData(params?: any): Observable<any> {
    const datas = [];

    for (let i = 0; i < 100; i++) {
      datas.push({
        code: '0' + i,
        lang: 'gb'
      });
    }
    return of(datas);
  }
}

